import{_ as o,o as t,c as r,a3 as a}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"91. Oncall Recall Non Catt","description":"","frontmatter":{"title":"91. Oncall Recall Non Catt","eba":"Mental Health Services 2024-2028","topics":["leave","public-holidays","allowances"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/hours-of-work/91-oncall-recall-non-catt.md","filePath":"ebas/mental-health/rpn-pen-mho/hours-of-work/91-oncall-recall-non-catt.md"}'),l={name:"ebas/mental-health/rpn-pen-mho/hours-of-work/91-oncall-recall-non-catt.md"};function n(s,e,i,p,h,c){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="_91-oncall-recall-non-catt" tabindex="-1">91. Oncall Recall Non Catt <a class="header-anchor" href="#_91-oncall-recall-non-catt" aria-label="Permalink to &quot;91. Oncall Recall Non Catt&quot;">​</a></h1><p><strong>91.1</strong> On-call Allowance</p><p><strong>(a)</strong> An Employee may be rostered to be ‘on call’.</p><p><strong>(b)</strong> On call means available to be recalled to duty in that period of time beyond the Employee’s rostered hours of duty.</p><p><strong>(c)</strong> An Employee rostered to be on-call will be paid the ‘on-call allowance’ set in Appendix 2 per 12-hour period or part thereof commencing with the following rates:</p><p><strong>(i)</strong> Monday to Friday- as per <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>.</p><p><strong>(ii)</strong> Saturday – as per <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a></p><p><strong>(iii)</strong> Sunday or public holiday – as per <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>; and</p><p><strong>(iv)</strong> Weekend public holiday – as per <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>.</p><p><strong>(d)</strong> The telephone allowance in the 2020 Agreement does not apply from FFPPOOA 20 May 2025 and has been included in the rates at 91.1(c) above.</p><p><strong>(e)</strong> An Employee rostered to be on-call for a period spanning two days over which two different on-call allowances apply will receive a payment which is equal to the allowance payable for the day attracting the higher allowance.</p><p><strong>91.2</strong> Recall – Return to Workplace</p><p><strong>(a)</strong> An Employee recalled to work during an off-duty period will be paid overtime for a minimum of three hours pay at the appropriate overtime rate where the work is not continuous with the next succeeding rostered period of duty.</p><p><strong>(b)</strong> An Employee recalled to work will not be required to work the full three hours if the work to be performed is completed in a shorter period.</p><p><strong>(c)</strong> Each period of recall under this clause within an on-call period will stand alone, provided that:</p><p><strong>(i)</strong> only the first period of recall within an on-call period will result in a lower overtime penalty (if applicable under subclause 91.2); and</p><p><strong>(ii)</strong> consecutive periods of on-call will be treated as a single period of on- call for the purposes of (i) above.</p><p><strong>(d)</strong> Subclause 91.2(b) above will not apply when overtime is continuous with the completion or commencement of that Employer’s rostered shift.</p><p><strong>(e)</strong> The time spent travelling to and from the place of duty will be deemed to be time worked.</p><p><strong>(f)</strong> From FFPPOOA 20 May 2025, if an Employee is recalled and is subsequently not required to commence work the Employee is entitled to the minimum payment at clause 91.1 above.</p><p><strong>(g)</strong> An Employee who is recalled to work outside ordinary rostered hours and who uses their own vehicle for transport from home to place of work and return shall receive the Vehicle Allowance.</p><p><strong>(h)</strong> If the Employee finishes any period of recall at a time when reasonable means of transport are not available for the Employee to return to their place of residence the Employer shall provide adequate transport free of cost to the Employee.</p><p><strong>91.3</strong> Recall – Without Return to Workplace</p><p><strong>(a)</strong> Where re-call to duty can be managed without the Employee having to return to their workplace, such as by telephone or computer, the Employee will be paid a minimum of one hour at the appropriate overtime rate for each occasion, provided that multiple recalls within a discrete hour will not attract additional payment.</p><p><strong>(b)</strong> Where the Employee is due to commence rostered ordinary hours within 4 hours of the completion of the call, and the cumulative recall work in the 8 hours immediately preceding rostered duty meets the following criteria:</p><p><strong>(i)</strong> has exceeded two hours work (rather than the time paid); or</p><p><strong>(ii)</strong> comprises 3 or more recalls over a period of 4 hours or more</p><p><strong>91.4</strong> the Employer will:</p><p><strong>(i)</strong> not require the Employee to resume or to continue to work without having had 10 consecutive hours off duty without loss of pay for rostered ordinary hours; or</p><p><strong>(ii)</strong> pay the Employee at the rate of double time until released from duty for 10 consecutive hours, without loss of pay for rostered ordinary hours occurring during such absence.</p>',30)])])}const m=o(l,[["render",n]]);export{u as __pageData,m as default};
